import React, { useState } from "react";
import { motion } from "framer-motion";

const Contact = () => {
  const [formData, setFormData] = useState({
    name: "",
    mobile: "",
    email: "",
    message: "",
  });

  const [status, setStatus] = useState(""); // success | error | sending

  // MODE TOGGLE: Set USE_BACKEND=true to use Node API, false for React-only (localStorage)
  // When you deploy the Node backend, change this to true or use env var
  const USE_BACKEND = process.env.REACT_APP_USE_BACKEND === "true";
  const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000/api/sendQuote";

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  // Save contact to localStorage (React-only mode)
  const saveToLocalStorage = () => {
    try {
      const contacts = JSON.parse(localStorage.getItem("contacts") || "[]");
      contacts.push({
        id: Date.now(),
        timestamp: new Date().toISOString(),
        ...formData,
      });
      localStorage.setItem("contacts", JSON.stringify(contacts));
      return true;
    } catch (err) {
      console.error("localStorage error:", err);
      return false;
    }
  };

  // Send to API (when backend is deployed)
  const sendToAPI = async () => {
    try {
      const res = await fetch(API_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: formData.name,
          mobile: formData.mobile,
          email: formData.email,
          message: formData.message
        }),
      });

      const data = await res.json();
      if (data.success || data.ok) {
        return true;
      } else {
        throw new Error(data.error || "API error");
      }
    } catch (err) {
      console.error("API error:", err);
      return false;
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setStatus("sending");

    let success = false;

    if (USE_BACKEND) {
      // Mode: Use Node API
      success = await sendToAPI();
    } else {
      // Mode: React-only (localStorage)
      success = saveToLocalStorage();
    }

    if (success) {
      setStatus("success");
      setFormData({ name: "", mobile: "", email: "", message: "" });
      setTimeout(() => setStatus(""), 4000);
    } else {
      setStatus("error");
      setTimeout(() => setStatus(""), 5000);
    }
  };

  return (
    <section id="contact" className="py-12 sm:py-20 bg-navy-50">
      <div className="px-4 mx-auto max-w-7xl">
        <motion.h2
          className="mb-8 text-3xl font-bold text-center sm:text-5xl sm:mb-12 text-navy-800"
          initial={{ y: -50 }}
          whileInView={{ y: 0 }}
          viewport={{ once: true }}
        >
          Contact Us
        </motion.h2>

        <motion.div
          className="grid grid-cols-1 gap-6 md:grid-cols-2 md:gap-12"
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          viewport={{ once: true }}
        >
          {/* ----- Contact Details ----- */}
          <div className="space-y-4 text-navy-700">
            <h3 className="text-xl font-bold sm:text-2xl">Details</h3>
            <p className="text-sm sm:text-base">
              <strong>Address:</strong> House No. 560, Shop No. 1, Ground Floor, 
              Hidayatour Afzalgarh, Bijnor, UP-246722
            </p>
            <p className="text-sm sm:text-base">
              <strong>Phone:</strong>{' '}
              <a href="tel:9899575231" className="text-blue-600 hover:underline">9899575231</a>
            </p>
            <p className="text-sm sm:text-base">
              <strong>Email:</strong>{' '}
              <a href="mailto:info@indiaadvertising.com" className="text-blue-600 hover:underline">info@indiaadvertising.com</a>
            </p>
            <p className="text-sm sm:text-base">
              <strong>Other Emails:</strong>{' '}
              <a href="mailto:shamim@indiaadvertising.com" className="text-blue-600 hover:underline">shamim@indiaadvertising.com</a>
              {' '}|{' '}
              <a href="mailto:naseem@indiaadvertising.com" className="text-blue-600 hover:underline">naseem@indiaadvertising.com</a>
            </p>
            <p className="text-sm sm:text-base">
              <strong>Website:</strong> www.indiadvertising.com
            </p>
          </div>

          {/* ----- Contact Form ----- */}
          <form onSubmit={handleSubmit} className="space-y-4">
            <input
              type="text"
              name="name"
              placeholder="Name"
              value={formData.name}
              onChange={handleChange}
              className="w-full p-3 border rounded sm:p-4 border-navy-300 focus:border-yellow-500 focus:outline-none"
              required
            />
            <input
              type="tel"
              name="mobile"
              placeholder="Mobile No."
              value={formData.mobile}
              onChange={handleChange}
              className="w-full p-3 border rounded sm:p-4 border-navy-300 focus:border-yellow-500 focus:outline-none"
              required
            />
            <input
              type="email"
              name="email"
              placeholder="Email"
              value={formData.email}
              onChange={handleChange}
              className="w-full p-3 border rounded sm:p-4 border-navy-300 focus:border-yellow-500 focus:outline-none"
              required
            />
            <textarea
              name="message"
              placeholder="Message"
              value={formData.message}
              onChange={handleChange}
              rows="3"
              className="w-full p-3 border rounded sm:p-4 border-navy-300 focus:border-yellow-500 focus:outline-none"
              required
            />
            <motion.button
              type="submit"
              disabled={status === "sending"}
              className={`w-full py-3 text-sm font-bold rounded text-navy-800 sm:py-4 sm:text-base neon-glow ${
                status === "sending" ? "bg-gray-400" : "bg-yellow-500"
              }`}
              whileHover={{ scale: 1.02 }}
            >
              {status === "sending" ? "Sending…" : "Send Message"}
            </motion.button>

            {/* ----- Feedback Toast ----- */}
            {status === "success" && (
              <p className="mt-2 text-center text-green-600">
                Message sent successfully!
              </p>
            )}
            {status === "error" && (
              <p className="mt-2 text-center text-red-600">
                Failed to send. Please try again.
              </p>
            )}
          </form>
        </motion.div>
      </div>
    </section>
  );
};

export default Contact;
